:root{
  --bg:#08111b;
  --panel:#0d1621;
  --panel2:#101b29;
  --line:rgba(255,255,255,.09);
  --text:#f7fbff;
  --muted:#c5ced8;
  --muted2:#9eaab8;
  --accent:#ff2323;
}
*{box-sizing:border-box}
html{scroll-behavior:smooth}
body{
  margin:0;
  font-family:Arial,Helvetica,sans-serif;
  color:var(--text);
  background:linear-gradient(180deg,#07111b 0%, #0a1521 100%);
}
a{text-decoration:none;color:inherit}
.page-shell{padding:0 8px 32px}
.topbar{
  height:76px;
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:18px;
  padding:0 20px;
  background:#eef1f4;
  color:#111;
  border-bottom:1px solid #d8dde3;
}
.brand{display:flex;align-items:center;gap:12px;font-weight:900;font-size:18px}
.brand-mark{
  width:36px;height:36px;border-radius:10px;display:grid;place-items:center;
  background:#ff2323;color:#fff;font-weight:900;
}
.topnav{display:flex;gap:28px;font-weight:700}
.topnav a:hover{color:#ff2323}
.nav-cta{background:#ff2323;color:#fff;padding:14px 18px;border-radius:8px;font-weight:800}

.hero-v11{
  position:relative;
  min-height:720px;
  overflow:hidden;
  display:grid;
  align-items:stretch;
}
.hero-media{position:absolute;inset:0}
.hero-media img{width:100%;height:100%;object-fit:cover;display:block;filter:contrast(1.05) brightness(.72)}
.hero-overlay{
  position:absolute;inset:0;
  background:linear-gradient(90deg, rgba(6,9,15,.92) 0%, rgba(6,9,15,.74) 36%, rgba(6,9,15,.22) 72%, rgba(6,9,15,.1) 100%);
}
.target{
  position:absolute;border:2px solid rgba(207,255,61,.45);border-radius:999px;
  width:90px;height:90px;animation:pulse 2.8s ease-out infinite;
}
.t1{left:61%;top:18%}
.t2{left:73%;top:47%}
.t3{left:46%;top:73%}
.t4{left:83%;top:29%}

.hero-content{position:relative;z-index:2;max-width:760px;padding:86px 56px 44px}
.hero-tag{display:inline-block;margin-bottom:20px;font-size:16px;font-weight:800;letter-spacing:.04em}
.hero-content h1{margin:0;max-width:700px;font-size:72px;line-height:.98;font-weight:900;letter-spacing:-.04em}
.hero-content p{max-width:700px;margin:18px 0 0;font-size:25px;line-height:1.35;color:var(--muted)}
.hero-actions{display:flex;gap:14px;flex-wrap:wrap;margin-top:28px}
.btn{display:inline-flex;align-items:center;justify-content:center;min-height:54px;padding:0 26px;border-radius:8px;font-weight:900;font-size:18px}
.btn-primary{background:var(--accent);color:#fff}
.btn-secondary{background:transparent;color:#fff;border:2px solid rgba(255,255,255,.8)}
.btn.full{width:100%}
.hero-proof{display:flex;gap:14px;flex-wrap:wrap;margin-top:28px}
.proof-box{min-width:180px;padding:16px 18px;border:1px solid rgba(255,255,255,.14);background:rgba(0,0,0,.28);backdrop-filter:blur(10px)}
.proof-box strong{display:block;font-size:28px;margin-bottom:6px}
.proof-box span{color:var(--muted2)}

.section{padding:74px 56px}
.section-dark{background:#0b131d}
.eyebrow{display:inline-block;margin-bottom:12px;color:#ff6c6c;font-size:14px;letter-spacing:.08em;font-weight:800;text-transform:uppercase}
.intro-copy h2,.section-head h2,.final-cta h2,.panel-copy h2{margin:0 0 12px;font-size:44px;line-height:1.03}
.intro-copy p,.section-head p,.cta-box p,.panel-copy p{margin:0;color:var(--muted);font-size:20px;line-height:1.5}
.intro-strip{
  display:grid;grid-template-columns:1.1fr .9fr;gap:28px;align-items:center;background:#0b131d;border-top:1px solid var(--line)
}
.mini-panel{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}
.mini-chip{padding:18px;background:linear-gradient(180deg,#101927,#0d1622);border:1px solid var(--line);font-weight:800}

.cards-section,.pricing-section,.final-cta{background:#09131e}
.cards-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}
.value-card,.price-card,.panel-card,.cta-box,.integration-note{
  background:linear-gradient(180deg,#101926,#0c1520);border:1px solid var(--line)
}
.value-card{padding:26px}
.icon-dot{width:18px;height:18px;border-radius:999px;background:#ff2323;margin-bottom:18px;box-shadow:0 0 0 10px rgba(255,35,35,.08)}
.value-card h3{margin:0 0 12px;font-size:30px;line-height:1.05}
.value-card p{margin:0;color:var(--muted);font-size:18px;line-height:1.6}

.panel-grid{display:grid;grid-template-columns:.9fr 1.1fr;gap:28px;align-items:start}
.kpis{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px;margin-top:22px}
.kpi{padding:18px;background:linear-gradient(180deg,#101927,#0d1622);border:1px solid var(--line)}
.kpi small{display:block;color:var(--muted2);margin-bottom:8px}
.kpi strong{font-size:32px}
.integration-note{margin-top:18px;padding:18px}
.integration-note strong{display:block;margin-bottom:8px;font-size:20px}
.panel-card{padding:18px}
.panel-card-head{display:flex;justify-content:space-between;align-items:end;margin-bottom:14px}
.panel-card-head span{color:#ff6c6c;font-weight:800;text-transform:uppercase;font-size:13px}
.panel-card-head strong{font-size:22px}
.live-map-wrap{position:relative;height:420px;border:1px solid var(--line);overflow:hidden;background:#081423}
.live-map-wrap .maplibregl-map{font:inherit}
.live-map-wrap .maplibregl-canvas{filter:contrast(1.04) brightness(.92)}
.live-map-wrap .maplibregl-ctrl-top-right{top:12px;right:12px}
.live-map-wrap .maplibregl-ctrl-group{border-radius:14px;overflow:hidden}
.map-overlay{
  position:absolute;inset:0;pointer-events:none;
  background:radial-gradient(circle at 22% 78%, rgba(0,255,149,.12), transparent 18%), linear-gradient(180deg, rgba(0,0,0,.05), rgba(0,0,0,.1));
}
.marker{position:relative;width:18px;height:18px}
.marker .ring,.marker .dot{position:absolute;border-radius:999px}
.marker .ring{inset:-10px;animation:pulse 2.2s ease-out infinite}
.marker .dot{inset:0}
.marker.active .ring{background:rgba(27,228,107,.18)}
.marker.active .dot{background:#1be46b;box-shadow:0 0 0 10px rgba(27,228,107,.08)}
.marker.idle .ring{background:rgba(46,211,255,.18)}
.marker.idle .dot{background:#2ed3ff;box-shadow:0 0 0 10px rgba(46,211,255,.08)}
.marker.offline .ring{background:rgba(255,35,35,.18)}
.marker.offline .dot{background:#ff2323;box-shadow:0 0 0 10px rgba(255,35,35,.08)}

.panel-bottom{display:grid;grid-template-columns:.9fr 1.1fr;gap:14px;margin-top:14px}
.vehicle-summary,.alerts-list{padding:18px;border:1px solid var(--line);background:#0b1521}
.vehicle-summary small,.alerts-list small{display:block;color:var(--muted2);margin-bottom:8px}
.vehicle-summary strong{display:block;font-size:30px;margin-bottom:8px}
.vehicle-summary span{color:var(--muted)}
.alert-row{padding:12px 0;border-top:1px solid rgba(255,255,255,.08)}
.alert-row:first-of-type{border-top:none}
.alert-row b{display:block;font-size:18px;margin-bottom:4px}
.alert-row span{color:var(--muted2)}
.alert-row.high b{color:#ff8b8b}
.alert-row.medium b{color:#ffd27d}
.alert-row.low b{color:#8bffc7}
.alert-row.empty{color:var(--muted)}

.pricing-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px}
.price-card{position:relative;padding:26px}
.price-card.featured{border-color:rgba(255,35,35,.55);box-shadow:0 0 0 1px rgba(255,35,35,.18) inset}
.badge{position:absolute;top:16px;right:16px;background:#ff2323;color:#fff;padding:8px 10px;border-radius:999px;font-size:12px;font-weight:800}
.price-card h3{margin:0 0 10px;font-size:30px}
.price{font-size:42px;font-weight:900;margin-bottom:16px}
.price-card ul{margin:0 0 22px;padding-left:18px;color:var(--muted);line-height:1.8}
.cta-box{text-align:center;padding:38px 26px}
.cta-box p{max-width:760px;margin:0 auto 24px}

@keyframes pulse{0%{transform:scale(.55);opacity:.9}100%{transform:scale(1.8);opacity:0}}
@media (max-width: 1100px){
  .hero-content h1{font-size:58px}
  .hero-content p{font-size:22px}
  .intro-strip,.panel-grid,.panel-bottom{grid-template-columns:1fr}
  .cards-grid,.pricing-grid{grid-template-columns:1fr 1fr}
}
@media (max-width: 760px){
  .topnav{display:none}
  .topbar{padding:0 14px}
  .page-shell{padding:0}
  .section{padding:54px 20px}
  .hero-v11{min-height:auto}
  .hero-content{padding:40px 20px 32px}
  .hero-content h1{font-size:42px}
  .hero-content p{font-size:20px}
  .hero-actions,.hero-proof{flex-direction:column}
  .btn,.proof-box{width:100%}
  .cards-grid,.pricing-grid,.mini-panel,.kpis,.panel-bottom{grid-template-columns:1fr}
  .live-map-wrap{height:340px}
}

.hero-gps {
  position: relative;
  display: grid;
  grid-template-columns: 1.15fr 0.95fr;
  min-height: 88vh;
  overflow: hidden;
  background:
    radial-gradient(circle at 20% 20%, rgba(31, 122, 140, 0.18), transparent 35%),
    linear-gradient(135deg, #07111a 0%, #091723 45%, #0c1d2a 100%);
}

.hero-media-gps {
  position: relative;
  overflow: hidden;
  min-height: 88vh;
  isolation: isolate;
  cursor: crosshair;
}

/* Imagen base */
.hero-image-base {
  position: absolute;
  inset: 0;
  background-image: url("/images/hero-road.jpg");
  background-size: cover;
  background-position: center;
  transform: scale(1.03);
  transition: transform 0.6s ease;
  will-change: transform;
}

.hero-media-gps:hover .hero-image-base {
  transform: scale(1.08);
}

/* Oscurece para que el texto respire */
.hero-media-gps .hero-overlay {
  position: absolute;
  inset: 0;
  background:
    linear-gradient(90deg, rgba(5, 13, 20, 0.72) 0%, rgba(5, 13, 20, 0.28) 42%, rgba(5, 13, 20, 0.55) 100%),
    linear-gradient(180deg, rgba(4, 10, 16, 0.20) 0%, rgba(4, 10, 16, 0.45) 100%);
  z-index: 1;
}

/* Glow del mouse */
.hero-glow {
  position: absolute;
  width: 280px;
  height: 280px;
  border-radius: 999px;
  transform: translate(-50%, -50%);
  pointer-events: none;
  z-index: 2;
  opacity: 0;
  transition: opacity 0.28s ease;
  background: radial-gradient(circle, rgba(62, 211, 255, 0.22) 0%, rgba(62, 211, 255, 0.10) 32%, rgba(62, 211, 255, 0) 70%);
  filter: blur(14px);
}

.hero-glow.active {
  opacity: 1;
}

/* Scanner / lupa */
.hero-scanner {
  position: absolute;
  width: 180px;
  height: 180px;
  border-radius: 50%;
  transform: translate(-50%, -50%) scale(0.9);
  pointer-events: none;
  z-index: 3;
  opacity: 0;
  overflow: hidden;
  transition:
    opacity 0.25s ease,
    transform 0.25s ease,
    box-shadow 0.25s ease;

  background-image: url("/images/hero-road.jpg");
  background-size: 190%;
  background-repeat: no-repeat;
  border: 1px solid rgba(127, 235, 255, 0.70);
  box-shadow:
    0 0 0 1px rgba(127, 235, 255, 0.18),
    0 0 24px rgba(60, 214, 255, 0.35),
    inset 0 0 30px rgba(0, 0, 0, 0.18);
}

.hero-scanner::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at center, rgba(255,255,255,0.08), transparent 58%),
    linear-gradient(180deg, rgba(62, 211, 255, 0.10), rgba(62, 211, 255, 0.02));
  z-index: 0;
}

.hero-scanner.active {
  opacity: 1;
  transform: translate(-50%, -50%) scale(1);
}

/* Anillos */
.scanner-ring {
  position: absolute;
  inset: 50%;
  border-radius: 50%;
  transform: translate(-50%, -50%);
  border: 1px solid rgba(127, 235, 255, 0.45);
}

.ring-1 {
  width: 68%;
  height: 68%;
  animation: pulseRing 2.2s infinite ease-out;
}

.ring-2 {
  width: 92%;
  height: 92%;
  opacity: 0.55;
  animation: pulseRing 2.8s infinite ease-out;
}

/* Cruz de tracking */
.scanner-cross {
  position: absolute;
  background: rgba(127, 235, 255, 0.75);
  box-shadow: 0 0 10px rgba(127, 235, 255, 0.45);
}

.cross-h {
  left: 50%;
  top: 50%;
  width: 56px;
  height: 1px;
  transform: translate(-50%, -50%);
}

.cross-v {
  left: 50%;
  top: 50%;
  width: 1px;
  height: 56px;
  transform: translate(-50%, -50%);
}

.scanner-dot {
  position: absolute;
  left: 50%;
  top: 50%;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  transform: translate(-50%, -50%);
  background: #9bf1ff;
  box-shadow: 0 0 12px rgba(155, 241, 255, 0.9);
}

/* Decoración */
.target {
  position: absolute;
  width: 18px;
  height: 18px;
  border: 1px solid rgba(120, 220, 255, 0.45);
  border-radius: 50%;
  z-index: 2;
  box-shadow: 0 0 18px rgba(45, 201, 255, 0.18);
}

.target::before,
.target::after {
  content: "";
  position: absolute;
  background: rgba(120, 220, 255, 0.55);
}

.target::before {
  width: 1px;
  height: 26px;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
}

.target::after {
  width: 26px;
  height: 1px;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
}

.t1 { top: 18%; left: 16%; }
.t2 { top: 32%; left: 72%; }
.t3 { top: 66%; left: 24%; }
.t4 { top: 78%; left: 78%; }

.hero-content {
  position: relative;
  z-index: 5;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 84px 64px 84px 24px;
}

.hero-tag {
  display: inline-flex;
  width: fit-content;
  margin-bottom: 18px;
  padding: 8px 14px;
  border-radius: 999px;
  border: 1px solid rgba(106, 207, 255, 0.20);
  background: rgba(10, 23, 34, 0.72);
  color: #9edfff;
  font-size: 0.84rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.hero-content h1 {
  margin: 0;
  font-size: clamp(2.6rem, 5vw, 5rem);
  line-height: 0.95;
  font-weight: 900;
  letter-spacing: -0.04em;
  color: #f4fbff;
}

.hero-content p {
  max-width: 620px;
  margin-top: 20px;
  font-size: 1.08rem;
  line-height: 1.7;
  color: rgba(227, 241, 249, 0.82);
}

.hero-actions {
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
  margin-top: 26px;
}

.hero-proof {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 14px;
  margin-top: 34px;
  max-width: 720px;
}

.proof-box {
  padding: 16px 16px;
  border-radius: 18px;
  border: 1px solid rgba(120, 188, 224, 0.16);
  background: rgba(11, 22, 31, 0.62);
  backdrop-filter: blur(8px);
}

.proof-box strong {
  display: block;
  font-size: 1.1rem;
  color: #ffffff;
}

.proof-box span {
  display: block;
  margin-top: 6px;
  font-size: 0.92rem;
  color: rgba(220, 234, 242, 0.78);
}

@keyframes pulseRing {
  0% {
    transform: translate(-50%, -50%) scale(0.96);
    opacity: 0.65;
  }
  70% {
    transform: translate(-50%, -50%) scale(1.04);
    opacity: 0.25;
  }
  100% {
    transform: translate(-50%, -50%) scale(0.96);
    opacity: 0.65;
  }
}

@media (max-width: 1100px) {
  .hero-gps {
    grid-template-columns: 1fr;
  }

  .hero-media-gps {
    min-height: 52vh;
  }

  .hero-content {
    padding: 40px 22px 56px;
  }

  .hero-proof {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 768px) {
  .hero-scanner,
  .hero-glow {
    display: none;
  }

  .hero-media-gps:hover .hero-image-base {
    transform: scale(1.03);
  }

  .hero-content h1 {
    font-size: clamp(2.2rem, 8vw, 3.4rem);
  }

  .hero-content p {
    font-size: 1rem;
    line-height: 1.6;
  }
}
